        "local_tasks": {},  # local_id -> Exchange ID
    }

def cmd_status(args: argparse.Namespace) -> None:
    """Show sync status and statistics."""
    state = get_sync_state()
    account = get_account()

    # Get counts from Exchange
    total_tasks = account.tasks.total_count

    # Count by status — fetch only needed fields to reduce payload
    status_only_tasks = list(account.tasks.all().only('status', 'due_date'))
    status_counts = {}
    for task in status_only_tasks:
        status = str(task.status)
        status_counts[status] = status_counts.get(status, 0) + 1

    # Count overdue
    now = datetime.now()
    overdue = sum(
        1
        for t in status_only_tasks
        if t.due_date
        and datetime(t.due_date.year, t.due_date.month, t.due_date.day) < now
        and str(t.status) != "Completed"
    )

    out(
        {
            "ok": True,
            "exchange": {
                "total": total_tasks,
                "by_status": status_counts,
                "overdue": overdue,
            },
            "sync": {
                "last_sync": state.get("last_sync"),
                "tracked_tasks": len(state.get("tasks", {})),
            },
            "account": account.primary_smtp_address,
        }
    )

def die(message) -> None:
    """Output error JSON to stdout and exit with error code.

    Args:
        message: String error message or dict with error details
    """
    if isinstance(message, dict):
        print(json.dumps(message, indent=2, default=str))
    else:
        print(json.dumps({"ok": False, "error": message}, indent=2))
    sys.exit(1)

def parse_datetime(date_str: Optional[str]) -> Optional[datetime]:
    """Parse date string in various formats."""
    if not date_str:
        return None

    formats = [
        "%Y-%m-%d",
        "%Y-%m-%d %H:%M",
        "%Y-%m-%d %H:%M:%S",
        "%Y-%m-%dT%H:%M",
        "%Y-%m-%dT%H:%M:%S",
        "%Y-%m-%dT%H:%M:%S.%f",
    ]
    for fmt in formats:
        try:
            return datetime.strptime(date_str, fmt)
        except ValueError:
            continue
    return None

def format_datetime(dt: Optional[datetime]) -> Optional[str]:
    """Format datetime for JSON output."""
    if dt is None:
        return None

    return dt.isoformat()

def mask_email(email: str) -> str:
    """Mask email for logging (show first char and domain)."""
    if not email or "@" not in email:
        return "***"
    local, domain = email.split("@", 1)
    return f"{local[0]}***@{domain}"

def parse_recipients(recipient_str: Optional[str]) -> List[str]:
    """Parse comma-separated recipient string into list."""
    if not recipient_str:
        return []
    return [addr.strip() for addr in recipient_str.split(",") if addr.strip()]

